import org.mockito.Mockito;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void setObjectToNumberStrategy_shouldSetStrategyAndReturnThis() throws Exception {
    ToNumberStrategy mockStrategy = mock(ToNumberStrategy.class);

    GsonBuilder returned = gsonBuilder.setObjectToNumberStrategy(mockStrategy);

    // Check returned object is the same instance (fluent API)
    assertSame(gsonBuilder, returned);

    // Use reflection to verify private field objectToNumberStrategy is set correctly
    Field field = GsonBuilder.class.getDeclaredField("objectToNumberStrategy");
    field.setAccessible(true);
    Object fieldValue = field.get(gsonBuilder);

    assertSame(mockStrategy, fieldValue);
  }

  @Test
  void setObjectToNumberStrategy_shouldThrowNullPointerException_whenNullArgument() {
    NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
      gsonBuilder.setObjectToNumberStrategy(null);
    });
    assertEquals("objectToNumberStrategy is marked non-null but is null", thrown.getMessage(), 
        "Expected NullPointerException with message from Objects.requireNonNull");
  }

  @Test
  void setObjectToNumberStrategy_reflectionInvokePrivateField() throws Exception {
    // Use reflection to call the method (even though public, to demonstrate reflection usage)
    ToNumberStrategy mockStrategy = mock(ToNumberStrategy.class);

    Method method = GsonBuilder.class.getDeclaredMethod("setObjectToNumberStrategy", ToNumberStrategy.class);
    method.setAccessible(true);
    Object returned = method.invoke(gsonBuilder, mockStrategy);

    assertSame(gsonBuilder, returned);

    Field field = GsonBuilder.class.getDeclaredField("objectToNumberStrategy");
    field.setAccessible(true);
    Object fieldValue = field.get(gsonBuilder);

    assertSame(mockStrategy, fieldValue);
  }
}
